(window.webpackJsonp=window.webpackJsonp||[]).push([[328],{955:function(n,t){n.exports="\x3c!-- \ntitle: CSS\nsort: \n--\x3e \n\n## 加特技\n\n```css\n// 渐变\nbackground: linear-gradient(to bottom right, #7ffb, #4bfb);\n// 阴影\n/* x偏移量 | y偏移量 | 阴影模糊半径 | 阴影扩散半径 | 阴影颜色 */\nbox-shadow: 7px 7px 10px 7px rgba(0, 0, 0, 0.2);\n// 文字阴影\n/* x偏移量 | y偏移量 | 阴影模糊半径  | 阴影颜色 */\ntext-shadow: 5px 5px 5px 5px #fffb;\n// 背景图\nbackground: url(bgimg.gif) no-repeat 5px 5px;\n\nmargin: style                  /*单值语法  所有边缘 */  举例： margin: 1em; \nmargin: vertical horizontal    /*二值语法  纵向 横向 */  举例： margin: 5% auto; \nmargin: top horizontal bottom  /*三值语法 上 横向 下*/  举例： margin: 1em auto 2em; \nmargin: top right bottom left  /*四值语法 上 右 下 左*/  举例： margin: 2px 1em 0 auto; \n\ntext-align: center;\t\t/* 文字居中 */\n```\n\n"}}]);